{"content": "<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>FamCloud Labs — Your Family's AI, At Home</title>
  <meta name="description" content="A private AI assistant for your household. Own your hardware. Own your data.">
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=Outfit:wght@400;600;700;800&display=swap" rel="stylesheet">
  <style>
    *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
    body {
      font-family: 'Inter', -apple-system, sans-serif;
      background: #0B0F1A;
      color: #f0f0f0;
      line-height: 1.6;
      -webkit-font-smoothing: antialiased;
    }
    a { color: #FF9F1C; text-decoration: none; }
    .container { max-width: 1080px; margin: 0 auto; padding: 0 28px; }

    /* NAV */
    nav {
      display: flex; align-items: center; justify-content: space-between;
      padding: 16px 28px; position: sticky; top: 0;
      background: rgba(11,15,26,0.92); backdrop-filter: blur(12px);
      border-bottom: 1px solid #1A1F35; z-index: 10;
    }
    .logo-wrap h1 {
      font-family: 'Outfit', sans-serif; font-size: 1.4rem; font-weight: 800;
      letter-spacing: -0.5px;
      background: linear-gradient(135deg, #FF9F1C, #FF6B6B);
      -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
    }
    .logo-wrap .labs {
      font-weight: 500; font-size: 0.85rem; -webkit-text-fill-color: #6B7FA3; margin-left: 4px;
    }
    .nav-email { color: #8899B8; font-size: 0.9rem; }
    .nav-email:hover { color: #FF9F1C; }

    /* HERO */
    .hero-wrap {
      background:
        radial-gradient(800px 400px at 50% -50%, rgba(124, 77, 255, 0.12) 0%, transparent 60%),
        radial-gradient(500px 300px at 75% 50%, rgba(255, 159, 28, 0.08) 0%, transparent 50%);
    }
    .hero { padding: 90px 0 70px; text-align: center; }
    .badge {
      display: inline-block; padding: 5px 12px; border-radius: 200px;
      font-size: 0.75rem; font-weight: 600; color: #FF9F1C;
      border: 1px solid rgba(255,159,28,0.3); background: rgba(255,159,28,0.1);
      margin-bottom: 24px;
    }
    .hero h2 {
      font-family: 'Outfit', sans-serif; font-size: clamp(2.4rem, 6.5vw, 3.8rem);
      font-weight: 800; letter-spacing: -1.5px; line-height: 1.1; max-width: 700px; margin: 0 auto;
    }
    .hero h2 .accent {
      background: linear-gradient(135deg, #FF9F1C, #FF6B6B);
      -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
    }
    .hero p { color: #8899B8; font-size: 1.05rem; max-width: 480px; margin: 14px auto 32px; }
    .cta-btn {
      display: inline-block; padding: 13px 28px; border-radius: 50px;
      background: linear-gradient(135deg, #FF9F1C, #FF7A3D);
      color: #0A0E1A; font-weight: 700; font-size: 1rem;
      transition: transform 0.2s; box-shadow: 0 4px 20px rgba(255,159,28,0.25);
    }
    .cta-btn:hover { transform: translateY(-2px); color: #0A0E1A; }

    /* SECTIONS */
    .section-label {
      font-size: 0.75rem; text-transform: uppercase; letter-spacing: 0.12em;
      font-weight: 600; margin-bottom: 8px;
      background: linear-gradient(135deg, #FF9F1C, #7C4DFF);
      -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
    }
    .section-title {
      font-family: 'Outfit', sans-serif;
      font-size: clamp(1.6rem, 4vw, 2.1rem); font-weight: 700;
      letter-spacing: -0.5px; margin-bottom: 32px;
    }

    /* EXAMPLES */
    .examples-section { padding: 60px 0 70px; }
    .examples-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 16px; }
    .example-card {
      background: linear-gradient(160deg, #111830, #0F1425);
      border: 1px solid #1E2745; border-radius: 14px; padding: 22px;
    }
    .example-card .emoji { font-size: 1.3rem; margin-bottom: 8px; display: block; }
    .example-card h3 { font-size: 0.95rem; font-weight: 700; margin-bottom: 6px; }
    .example-card p { color: #8899B8; font-size: 0.88rem; line-height: 1.45; }
