    .example-card .after { color: #C4D0E8; }
    .arrow { color: #FF9F1C; margin: 0 4px; font-style: normal; }

    /* FEATURES */
    .features-section { padding: 50px 0 70px; }
    .features-row { display: flex; gap: 16px; flex-wrap: wrap; }
    .feature-tag {
      display: inline-flex; align-items: center; gap: 6px;
      padding: 8px 14px; border-radius: 10px;
      background: linear-gradient(160deg, #111830, #0F1425);
      border: 1px solid #1E2745; font-size: 0.9rem; font-weight: 500;
    }
    .feature-tag .dot { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; }
    .dot-purple { background: #7C4DFF; }
    .dot-orange { background: #FF9F1C; }
    .dot-green { background: #4ADE80; }
    .dot-pink { background: #FF6B6B; }
    .dot-blue { background: #3B82F6; }
    .dot-cyan { background: #22D3EE; }

    /* PRICING */
    .pricing-section { padding: 60px 0 70px; }
    .pricing-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 18px; }
    .pricing-card {
      background: linear-gradient(160deg, #111830, #0F1425);
      border: 1px solid #1E2745; border-radius: 16px; padding: 28px 24px;
      position: relative;
    }
    .pricing-card.popular {
      border-color: #FF9F1C;
      box-shadow: 0 0 30px rgba(255,159,28,0.15);
    }
    .pricing-card.popular::before {
      content: 'Most Popular';
      position: absolute; top: -11px; left: 50%; transform: translateX(-50%);
      background: linear-gradient(135deg, #FF9F1C, #FF7A3D);
      color: #0A0E1A; font-size: 0.7rem; font-weight: 700;
      padding: 3px 12px; border-radius: 200px; text-transform: uppercase;
      letter-spacing: 0.05em;
    }
    .pricing-card h3 {
      font-family: 'Outfit', sans-serif; font-size: 1.1rem; font-weight: 700; margin-bottom: 4px;
    }
    .pricing-card .price { font-size: 2.2rem; font-weight: 800; letter-spacing: -1px; margin: 8px 0; }
    .pricing-card .price small { font-size: 0.95rem; font-weight: 400; color: #6B7FA3; }
    .pricing-card .setup { font-size: 0.8rem; color: #6B7FA3; margin-bottom: 16px; }
    .pricing-card ul { list-style: none; padding: 0; }
    .pricing-card li {
      font-size: 0.88rem; padding: 7px 0; border-bottom: 1px solid #1A1F35; color: #C4D0E8;
    }
    .pricing-card li:last-child { border: none; }
    .pricing-card .cta-btn-sm {
      display: block; text-align: center; margin-top: 16px;
      padding: 10px 20px; border-radius: 50px;
      background: rgba(255,159,28,0.15); color: #FF9F1C;
      font-weight: 600; font-size: 0.9rem; border: 1px solid rgba(255,159,28,0.25);
      transition: background 0.2s;
    }
    .pricing-card .cta-btn-sm:hover { background: rgba(255,159,28,0.25); color: #FF9F1C; }
    .pricing-card.popular .cta-btn-sm {
      background: linear-gradient(135deg, #FF9F1C, #FF7A3D);
      color: #0A0E1A; border: none;
    }

    /* HOW IT WORKS */
    .how-section { padding: 50px 0 70px; }
    .how-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; }
    .how-step { text-align: center; padding: 24px 16px; }
    .step-num {
      display: inline-flex; align-items: center; justify-content: center;
      width: 40px; height: 40px; border-radius: 50%;
      background: linear-gradient(135deg, rgba(124,77,255,0.2), rgba(255,159,28,0.2));
      border: 1px solid rgba(124,77,255,0.3);
      color: #C4B5FD; font-weight: 700; font-size: 1rem; margin-bottom: 12px;
    }
    .how-step h3 { font-family: 'Outfit'; font-size: 1rem; font-weight: 700; margin-bottom: 6px; }
    .how-step p { color: #8899B8; font-size: 0.9rem; }

    /* BOTTOM CTA */
    .bottom-cta { padding: 60px 0 50px; }
    .bottom-cta-wrap {
      background: linear-gradient(160deg, #111830, #0D1224);
      border: 1px solid #1E2745; border-radius: 20px;
      padding: 48px 32px; text-align: center; position: relative; overflow: hidden;
    }
    .bottom-cta-wrap::before {
      content: ''; position: absolute; top: -80px; right: -80px;
      width: 250px; height: 250px;
      background: radial-gradient(circle, rgba(255,159,28,0.08), transparent 70%);
      pointer-events: none;
